& { $ErrorActionPreference='Continue'; $root=(Resolve-Path -LiteralPath (Get-Location).Path).Path.TrimEnd('\','/'); $dist=Join-Path $root 'dist'; $sb=[System.Text.StringBuilder]::new(); [void]$sb.AppendLine('DIST AUDIT'); [void]$sb.AppendLine('ROOT: ' + $root); if(!(Test-Path -LiteralPath $dist)){ [void]$sb.AppendLine('DIST NOT FOUND'); $result=$sb.ToString(); try { Set-Clipboard -Value $result } catch {}; Write-Host 'dist not found'; return }; $files=Get-ChildItem -LiteralPath $dist -Recurse -File -Force | Sort-Object FullName; $total=(($files | Measure-Object Length -Sum).Sum); [void]$sb.AppendLine('FILES: ' + $files.Count); [void]$sb.AppendLine('TOTAL SIZE: ' + [Math]::Round($total/1MB,2) + ' MB'); foreach($f in ($files | Sort-Object Length -Descending)){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); [void]$sb.AppendLine($rel + ' | ' + $f.Extension + ' | ' + [Math]::Round($f.Length/1KB,2) + ' KB') }; $result=$sb.ToString(); try { Set-Clipboard -Value $result } catch {}; Write-Host ('copied chars: ' + $result.Length); Write-Host ('dist files indexed: ' + $files.Count) }
